				logger.debug("userInfo: {}", doGet2);

				// 用获取到的用户信息进行自己体系的登录
				if (StringUtils.isNotBlank(doGet2)) {
					WechatUser user = JSONObject.parseObject(doGet2, WechatUser.class);
					logger.debug("user: {}", user);

